import React, { useState, useEffect } from 'react';
import './Navbar.css';

// 1. Import your logo image here. Adjust the path and filename to match exactly where your image is saved.
import brandLogo from '../assets/images/rednspice-logo.png'; 

const Navbar = ({ currentPage, setCurrentPage }) => {
  const [scrolled, setScrolled] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navLinks = ['Home', 'Menu', 'About', 'Contact'];

  return (
    <nav className={`navbar ${scrolled ? 'scrolled' : ''}`}>
      <div className="navbar-inner">

        {/* 2. Replace the old icon/text divs with an img tag */}
        <div className="logo" onClick={() => setCurrentPage('Home')} style={{ cursor: 'pointer' }}>
          <img src={brandLogo} alt="Rednspice Logo" className="logo-img" />
        </div>

        <ul className={`nav-links ${menuOpen ? 'open' : ''}`}>
          {navLinks.map(link => (
            <li key={link}>
              <button
                className={`nav-link ${currentPage === link ? 'active' : ''}`}
                onClick={() => { setCurrentPage(link); setMenuOpen(false); }}
              >
                {link}
              </button>
            </li>
          ))}
          <li>
            <button className="nav-order-btn" onClick={() => { setCurrentPage('Menu'); setMenuOpen(false); }}>
              Order Now
            </button>
          </li>
        </ul>

        <button className={`hamburger ${menuOpen ? 'open' : ''}`} onClick={() => setMenuOpen(!menuOpen)}>
          <span /><span /><span />
        </button>
      </div>
    </nav>
  );
};

export default Navbar;
